window.__QUIZ_DATA__=[{"id":"objective>Biology>2019>1","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Which of the following structures will not be found in the nucleus of a cell?","images":[],"options":{"A":"DNA","B":"Nucleolus","C":"Lysosome","D":"Centriole"},"answer":"C","explanation":"Lysosome is an extranuclear cell organelle, i.e it is found outside the nucleus. The orgaelles found within the nucleus include \u21d2 Chromosome (DNA), nucleolus, centriole, chromatin, mRNA.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>2","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"An example of organ level of organization is","images":[],"options":{"A":"bird","B":"kidney","C":"spermatozoon","D":"xylem"},"answer":"B","explanation":"Kidney is the organ level of organization.  Xylem is in the tissue level of organization  Bird is in the organism level of organization  Spermatozoon is in the cellular level of organization.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>3","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : FORMS IN WHICH LIVING CELLS EXIST","question":"A structural similarity between Paramecium and Amoeba is the presence of","images":[],"options":{"A":"one food vacuole","B":"two contractile vacuoles","C":"two nuclei","D":"one gullet"},"answer":"A","explanation":"A structural similarity between Paramecium and Amoeba is the presence of one food vacuole.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>4","subject":"Biology","year":"2019","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"The classes of plants the root systems in diagrams I and II below represent respectively are","images":["data:image/png;base64,"],"options":{"A":"Dicotyledoneae and Monocotyledoneae","B":"Monocotyledoneae and Dicotyledoneae","C":"Dicotyledoneae and Dicotyledoneae","D":"Monocotyledoneae and Monocotyledoneae"},"answer":"A","explanation":"It should be noted that the root systems of monocots and dicots differ in that dicots have a tap root system while monocots have a fibrous root system.  In the diagrams given, I and II represent dicotyledoneae and monocotyledoneae respectively.  dicotyledon has a tap root while monocotyledon has fibrous root","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>5","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"The diagram below is an illustration of a stage in a biological process. Study it and answer this question      What stage of cell division is illustrated in the diagram?","images":["data:image/png;base64,"],"options":{"A":"Prophase","B":"Metaphase","C":"Anaphase","D":"Telophase"},"answer":"C","explanation":"The diagram represents \"anaphase\".  Anaphase is a stage of mitosis after the metaphase, when replicated chromosomes are split and the newly-copied chromosomes are moved to opposite poles of the cell.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>6","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"The diagram below is an illustration of a stage in a biological process. Study it and answer this question    The part labelled I is the","images":["data:image/png;base64,"],"options":{"A":"centromere","B":"spindle fibre","C":"centriole","D":"chiasmata"},"answer":"C","explanation":"The part labelled I is the centriole. Centrioles are cylindrical structures found in animal cells that play a crucial role during cell division, particularly in mitosis. Centrioles are  located at the poles of the cell during certain stages of mitosis. centrioles are essential for the accurate and equal distribution of chromosomes to daughter cells during mitosis.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>7","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"The rate of diffusion of molecules between two media will be higher if","images":[],"options":{"A":"the difference in concentration of the two media is low.","B":"the difference in concentration of the two media is negligible.","C":"the difference in concentration of the two media is high.","D":"there is no difference in the concentration of the two media."},"answer":"C","explanation":"According to the principle of diffusion, molecules move from an area of higher concentration to an area of lower concentration. Therefore, the rate of diffusion will be higher if the difference in concentration of the two media is high.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>8","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Anaerobic respiration in the organism illustrated in the diagram below produces carbon dioxide and","images":["data:image/png;base64,"],"options":{"A":"ethanol.","B":"water.","C":"oxygen.","D":"glucose."},"answer":"A","explanation":"Anaerobic respiration produces carbon dioxide and ethanol.  N.B: Anaerobic respiration breaks down glucose (in the absence of oxygen) to give CO2 and C2H5OH.  C6H12O6 \u2192 2C2H5OH + 2CO2  \u21d2 (Glucose) \u2192 [Ethanol] + [Carbon dioxide]","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>9","subject":"Biology","year":"2019","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Underground storage stems which grow horizontally in the soil are","images":[],"options":{"A":"bulbs.","B":"runners.","C":"rhizomes.","D":"corms."},"answer":"C","explanation":"Rhizomes are a type of plant stem situated either at the soil surface or underground that contain nodes from which roots and other shoots originate. They grow horizontally in the soil, allowing the plant to propagate or survive underground during unfavorable seasons. Bulbs, runners, and corms are also types of plant stems, but they do not specifically grow horizontally underground.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>10","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Muscle fatigue in the body of an athlete is due to","images":[],"options":{"A":"low pH.","B":"high oxygen content.","C":"accumulation of lactic acid.","D":"accumulation of carbonic acid."},"answer":"C","explanation":"Muscle fatique in the body of an athlete is due to accumulation of lactic acid.  It should be noted that it is the lactic acid that causes pains in the muscles.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>11","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"The heart can beat continuously without being fatigued because it is composed of","images":[],"options":{"A":"skeletal muscles","B":"smooth muscles","C":"cardiac muscles","D":"renal muscles"},"answer":"C","explanation":"The heart is composed of cardiac muscles. Cardiac muscles are a type of muscle tissue that is found only in the heart and is responsible for pumping blood throughout the body. Cardiac muscle tissue, like skeletal muscle tissue, appears striated or striped. The cells of cardiac muscle tissue are connected to each other through intercalated discs, which allow the synchronization of the heart beat. This unique feature of cardiac muscles helps the heart to beat continuously without fatigue.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>12","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"The products of tissue respiration are","images":[],"options":{"A":"glucose, oxygen and water.","B":"oxygen, water and energy.","C":"glucose, carbon dioxide and energy.","D":"water, carbon dioxide and energy."},"answer":"D","explanation":"The products of tissue respiration are water, carbondixode and energy. It should be noted that \"tissue respiration\" according to the context of the question implies aerobic respiration.  C6H12O6 + 6O2 \u2192 6CO2 + 6H2O + 38ATP.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>13","subject":"Biology","year":"2019","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Excretory products in plants responsible for the the colouration of flowers are called","images":[],"options":{"A":"alkaloids.","B":"tannins.","C":"anthocyanins.","D":"resins."},"answer":"C","explanation":"Anthocyanins are polyphenols which are found in plants as red pigments. Anthocyanins are responsible for the blue, purple, red, and intermediate colors of many flowers, leaves, vegetables, and fruits. Nearly one thousand anthocyanins, and more than 15 anthocyanidins, exist in the vegetal kingdom.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>14","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"The process of maintaining a steady internal environment is known as","images":[],"options":{"A":"osmoregulation","B":"equilibration","C":"homeostasis","D":"plasmolysis"},"answer":"C","explanation":"Homeostasis is the process through which organisms maintain a stable internal environment, despite changes in external environmental conditions. This process involves the regulation of various aspects such as temperature, pH, and glucose concentration. Osmoregulation is a type of homeostasis that involves the regulation of water levels and mineral salts in the blood. Equilibration is the process of reaching equilibrium or balance, while plasmolysis is the process in plant cells where the cytoplasm pulls away from the cell wall due to the loss of water through osmosis.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>15","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Which of the following statements is not true about hormones?","images":[],"options":{"A":"Their responses are voluntary","B":"They may affect more than one target organ","C":"They are chemical messengers in animals","D":"They are transported by the blood to the target organs"},"answer":"A","explanation":"Hormones are chemical substances produced in the body that control and regulate the activity of certain cells or organs. Their responses are not voluntary but rather automatic and involuntary. They are indeed transported by the blood to the target organs and can affect more than one target organ.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>16","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"The diagram below is an illustration of human brain. Study it and answer this question      The part labelled I is the","images":["data:image/png;base64,"],"options":{"A":"olfactory lobe.","B":"cerebellum.","C":"cerebrum.","D":"medulla oblongata."},"answer":"C","explanation":"The part labelled I is the cerebrum. The cerebrum is the largest part of the brain and is responsible for most of the brain's complex functions. It is divided into two hemispheres, the left and right, and has several distinct regions and structures.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>17","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION","question":"The diagram below is an illustration of human brain. Study it and answer this question    The function of the part labelled II is that it controls","images":["data:image/png;base64,"],"options":{"A":"posture and balance of body.","B":"all voluntary actions.","C":"temperature and appetite.","D":"many involuntary actions."},"answer":"D","explanation":"The part labelled II is the medulla oblongata, it mainly controls involuntary actions such as vomiting, sneezing, etc.  It should be noted that the diagram is the dorsal view of a rabbit brain","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>18","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"To focus on a distant object, the ciliary muscle of the eye","images":[],"options":{"A":"contracts and the eye lens gets thicker.","B":"relaxes and the eye lens gets thinner.","C":"contracts and the eye lens gets thinner.","D":"relaxes and the eye lens gets thicker."},"answer":"B","explanation":"To focus on a distant object, the ciliary muscle of the eye relaxes which allows the lens to get thinner. This is because the light from distant objects is nearly parallel and needs less refraction to focus on the retina. This is a process known as accommodation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>19","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The main function of the amniotic fluid is for","images":[],"options":{"A":"respiration in the foetus.","B":"protection of the foetus from shock.","C":"lubricating the birth canal.","D":"nourishing the foetus."},"answer":"B","explanation":"The main function of the amniotic fluid is for protection of the foetus from shock.  The amniotic fluid is the protective fluid contained by the amniotic sac of a gravid amniote. This fluid serves as a cushion for the growing foetus, but also serves to facilitate the exchange of nutrients, water and biochemical products between mother and foetus.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>20","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of the longitudinal section of a flower. Study it and answer this question      Which part of the flower is responsible for the protection of young flower buds?","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"It should be noted that sepals protect the flower bud and are behind/underneath the petals when the flower opens.  The sepal is the part labelled II.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>21","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagram below is an illustration of the longitudinal section of a flower. Study it and answer this question    The essential parts of the flower are labelled","images":["data:image/png;base64,"],"options":{"A":"I, II and III.","B":"II, III and IV.","C":"III, V and VI.","D":"IV, V and VI."},"answer":"D","explanation":"The essential parts of a flower include:  Stamen   - Pollen  - Anther  - Filament     Carpel  - Ovary  - Stigma  - Style    IV - Ovary, V - Filament and VI - Ovary","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>22","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Deficiency in insulin could lead to","images":[],"options":{"A":"cirrhosis.","B":"hepatitis.","C":"diabetes.","D":"nephritis."},"answer":"C","explanation":"Insulin is produced by the \u03b1- cells of the pancreas to regulate high blood glucose level which could lead to diabetes, deficiency of insulin will disturb the homoestatic regulation of the blood glucose level thereby causing hyperglycaemia or diabetes.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>23","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"Which of the following forms of energy is utilized during photosynthesis?","images":[],"options":{"A":"Potential","B":"Kinetic","C":"Solar","D":"Chemical"},"answer":"C","explanation":"Solar energy is utilized during photosynthesis. In photosynthesis, carbon (IV) oxide and water use the energy from sunlight (trapped by chlorophyl) to initiate a reaction that will lead to the formation of glucose, and giving off oxygen as a by-product.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>24","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Light is excluded from a water culture experiment in order to","images":[],"options":{"A":"prevent overheating of the roots.","B":"enable the roots to grow straight down.","C":"prevent ionization of water molecules.","D":"prevent the growth of algae."},"answer":"D","explanation":"In a water culture experiment, light is excluded to prevent the growth of algae. Algae are photosynthetic organisms that require light to grow. If light is present, algae can overgrow and compete with the plant for nutrients, potentially affecting the results of the experiment.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>25","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"The major mineral present in the shell of Molluscs is","images":[],"options":{"A":"copper.","B":"sodium.","C":"iron.","D":"calcium."},"answer":"D","explanation":"The major mineral present in the shell of Molluscs is calcium. Molluscs, like snails and clams, have shells that are primarily made up of calcium carbonate. This mineral gives the shell its hardness and durability.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>26","subject":"Biology","year":"2019","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The digestion of proteins starts in the","images":[],"options":{"A":"small intestine.","B":"stomach.","C":"large intestine.","D":"mouth."},"answer":"B","explanation":"The digestion of proteins starts in the stomach. The stomach secretes an enzyme called pepsin, which breaks down proteins into smaller peptides. This is the first step in protein digestion. The process continues in the small intestine, where other enzymes further break down these peptides into amino acids.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>27","subject":"Biology","year":"2019","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Tooth decay is usually caused by","images":[],"options":{"A":"undigested and absorbed food.","B":"eating limited amount of sweetened food.","C":"the bacteria in the mouth that metabolize sugar to acids.","D":"eating a lot of proteinous foods."},"answer":"C","explanation":"Tooth decay is usually caused by the bacteria in the mouth that metabolize sugar to acids. This is because when you eat foods containing sugars, the bacteria in your mouth digest these sugars and produce acids. These acids can eat away at the hard, outer layer of your teeth, called enamel, leading to tooth decay.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>28","subject":"Biology","year":"2019","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"The conversion of ammonium salts into nitrates is called","images":[],"options":{"A":"putrefaction.","B":"denitrification.","C":"fixation.","D":"nitrification."},"answer":"D","explanation":"The conversion of ammonium salts into nitrates is called nitrification. Nitrification is a process by which ammonia is oxidized to nitrites (NO2-) and then to nitrates (NO3-) by bacteria. This process naturally occurs in the environment, where it is an important step in the nitrogen cycle.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>29","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL FACTORS","question":"The salinity of a brackish habitat","images":[],"options":{"A":"increases immediately after rainfall.","B":"increases at the end of the rainy season.","C":"decreases with an increase in the number of organisms.","D":"increases during the dry season."},"answer":"D","explanation":"The salinity of a brackish habitat increases during the dry season. This is because during the dry season, the rate of evaporation is higher than the rate of precipitation. As water evaporates, it leaves behind salts, thereby increasing the salinity of the habitat.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>30","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"If 90 ants are found in a field with a total area of 100m2, what is the population density of the ants?","images":[],"options":{"A":"0.09","B":"0.90","C":"9.00","D":"90.00"},"answer":"B","explanation":"Parameters give:  Number of organisms (ants) = 90  Total area = 100m2  Population density = ?  Recall:Populationdensity=No. of organismsLand area  P.D=90100=0.90","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>31","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The complex relationship between the members of a community and their physical environment is known as","images":[],"options":{"A":"commensalism.","B":"symbiosis.","C":"saprophytism.","D":"ecology."},"answer":"D","explanation":"Ecology is the branch of biology that deals with the relations of organisms to one another and to their physical surroundings. So, the complex relationship between the members of a community and their physical environment is known as ecology.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>32","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"The specific role of a species within its environment is known as its","images":[],"options":{"A":"habitat.","B":"niche.","C":"trophic level.","D":"biotic community."},"answer":"B","explanation":"In ecology, a niche is the role or job of a species in a habitat. The niche involves the species' interactions with the other members of its ecosystem, including its diet, its behaviours, and its influence on the environment and other species.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>33","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Which of the following soil fertility improvement methods will have the most negative effect on the ecosystem if not controlled?","images":[],"options":{"A":"Application of N-P-K fertilizer","B":"Shifting cultivation","C":"Mixed farming","D":"Crop rotation"},"answer":"A","explanation":"The application of N-P-K fertilizers can have the most negative effect on the ecosystem if not controlled because it can lead to:  Water Pollution: Runoff causes eutrophication, harming aquatic life.  Soil Degradation: Overuse leads to soil acidification and structural damage.  Air Pollution: Volatilization contributes to greenhouse gas emissions.  In contrast, shifting cultivation, mixed farming, and crop rotation generally have less harmful or even beneficial effects on the ecosystem when managed properly.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>34","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Organisms in an ecosystem are usually grouped according to their trophic level into","images":[],"options":{"A":"carnivores and omnivores.","B":"consumers and parasites.","C":"producers and saprophytes.","D":"producers and consumers."},"answer":"D","explanation":"In an ecosystem, organisms are grouped according to their trophic level into producers and consumers. Producers, also known as autotrophs, are organisms that can produce their own food from inorganic substances using light (photosynthesis) or chemical energy (chemosynthesis). Consumers, also known as heterotrophs, are organisms that cannot produce their own food and need to consume other organisms. Consumers can be further divided into primary consumers (herbivores), secondary consumers (carnivores and omnivores), and tertiary consumers (top predators).","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>35","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"In the pyramid of energy illustrated below, the organism with the least amount of transferred energy is","images":["data:image/png;base64,"],"options":{"A":"Spirogyra","B":"tadpole","C":"fish","D":"bird"},"answer":"C","explanation":"In a pyramid of energy, the organism with the least amount of transferred energy is: Bird  In a pyramid of energy, energy is transferred from one trophic level to the next, but with each transfer, a significant amount of energy is lost, primarily as heat. Therefore, higher trophic levels receive less energy than the levels below them.     First level (Spirogyra): Primary producers that capture the most energy from the sun.  Second level (Tadpole): Primary consumers that get energy from eating producers.  Third level (Fish): Secondary consumers that eat primary consumers.  Fourth level (Bird): Tertiary consumers that eat secondary consumers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>36","subject":"Biology","year":"2019","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Tall trees with unbranched trunks which grow above the upper storey of the forest are commonly referred to as","images":[],"options":{"A":"emergents.","B":"herbs.","C":"lianes.","D":"shrubs."},"answer":"A","explanation":"In a forest, the tallest trees with unbranched trunks that grow above the upper storey are referred to as 'emergents'. This term is used in the context of forest ecology to describe trees that grow taller than the average canopy height, allowing them to receive more sunlight than other trees. They are a key component of the forest ecosystem, providing habitat for many species and playing a significant role in nutrient cycling.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>37","subject":"Biology","year":"2019","type":"Objective","topic":"ECOLOGY OF POPULATION : PRESERVATION AND STORAGE OF FOODS","question":"Maize grain are best stored against insect attacks by","images":[],"options":{"A":"keeping in a silo.","B":"storing in the room.","C":"leaving them on their cobs.","D":"covering with leaves."},"answer":"A","explanation":"Maize grains are best stored against insect attacks by keeping them in a silo. A silo is a structure for storing bulk materials, often used in agriculture to store grain. Silos protect the grains from weather and pests. The other options do not provide the same level of protection against insects. Storing in the room or leaving them on their cobs exposes the grains to pests, and covering with leaves is not a reliable method of protection.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>38","subject":"Biology","year":"2019","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"Cholera is mostly spread by","images":[],"options":{"A":"air.","B":"soil.","C":"water.","D":"noise."},"answer":"C","explanation":"Cholera is an infectious disease that causes severe watery diarrhea, which can lead to dehydration and even death if untreated. It is caused by eating food or drinking water contaminated with a bacterium called Vibrio cholerae. The disease is most often spread through water contaminated with the bacteria. Therefore, the correct answer is 'water'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>39","subject":"Biology","year":"2019","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Which of the following resources is renewable?","images":[],"options":{"A":"Petroleum","B":"Coal","C":"Iron","D":"Trees"},"answer":"D","explanation":"Renewable resources are resources that can be replaced naturally and can be used again. Examples are: wind, solar, geothermal, biomass, and hydropower. Non-renewable resources, on the other hand, are those that cannot be replenished (made again) in a short period of time. Examples are: petroleum, coal, and iron. Therefore, the correct answer is 'Trees' as they can be replanted and regrown.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>40","subject":"Biology","year":"2019","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Which of the following roles is not performed by a government agency responsible for forest maintenance?","images":[],"options":{"A":"Regulating the harvest of timber and poaching.","B":"Creating, protecting and managing the forest reserves.","C":"Tracking the movement of timber, wood and wildlife.","D":"Regulating mining activities in the forest."},"answer":"D","explanation":"Government agencies responsible for forest maintenance primarily focus on conservation, management, and regulation related to forests and wildlife. While they may have some oversight related to land use and environmental impacts, direct regulation of mining activities is typically handled by specialized agencies focused on mining and minerals.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2019>41","subject":"Biology","year":"2019","type":"Objective","topic":"VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS","question":"Which of the following factors is not a source of variation in living organisms?","images":[],"options":{"A":"Environment","B":"Inheritance","C":"Mitosis","D":"Meiosis"},"answer":"C","explanation":"Variation in living organisms is caused by several factors, including the environment, inheritance, and meiosis. The environment can cause variations as organisms adapt to different conditions. Inheritance leads to variation as organisms inherit different combinations of genes from their parents. Meiosis, a type of cell division that results in four daughter cells each with half the number of chromosomes of the parent cell, also leads to variation as it results in new combinations of genes. However, mitosis, a type of cell division that results in two daughter cells each having the same number and kind of chromosomes as the parent nucleus, does not lead to variation as it produces identical cells. Therefore, option 3 is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>42","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"Individuals with blood group AB can donate blood to individuals with blood group(s)","images":[],"options":{"A":"A and B.","B":"A and O.","C":"AB only.","D":"O only."},"answer":"C","explanation":"Individuals with blood group AB are universal recipients, meaning they can receive blood from any group. However, they can only donate blood to individuals with the same blood group, AB. This is due to the presence of both A and B antigens on the red blood cells of AB individuals. If they were to donate to a person with blood group A or B, the recipient's antibodies would react with the donor's antigens, causing a transfusion reaction.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>43","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The diagram below is an illustration of a process occurring in a living animal cell.  Study it and answer this question      The process occurs in the","images":["data:image/png;base64,"],"options":{"A":"nucleus.","B":"mitochondrion.","C":"Golgi body.","D":"Cytoplasm."},"answer":"A","explanation":"The process depicted in the diagram is replication of DNA. It occurs in the nucleus.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>44","subject":"Biology","year":"2019","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The diagram below is an illustration of a process occurring in a living animal cell.  Study it and answer this question    The process is called","images":["data:image/png;base64,"],"options":{"A":"replication.","B":"cell maturation.","C":"crossing over.","D":"mutation."},"answer":"A","explanation":"The process is called replication of DNA. DNA replication is the process by which a double-stranded DNA molecule is copied to produce two identical DNA molecules.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>45","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following nucleotides is not found in the DNA molecule?","images":[],"options":{"A":"Adenine","B":"Cytosine","C":"Granine","D":"Uracil"},"answer":"D","explanation":"DNA (Deoxyribonucleic acid) is a molecule composed of two chains that coil around each other to form a double helix carrying genetic instructions. It is made up of four types of nucleotides: Adenine (A), Thymine (T), Cytosine (C), and Guanine (G). Uracil is not found in DNA; it is instead a component of RNA (Ribonucleic acid), where it pairs with Adenine.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>46","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a complete dominance monohybrid cross between a pure breeding yellow flowered plant Y and a pure breeding white flowered plant y, the result of the first filial generation is","images":[],"options":{"A":"50% yellow flowers.","B":"75% yellow flowers.","C":"all yellow flowers.","D":"all white flowers."},"answer":"C","explanation":"The result of the filial generation is heterozygous yellow flowers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>47","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"A man whose blood group is heterozygous B is married to a woman whose blood group is also heterozygous B. Which of the following statements is correct about the blood group of their four offspring?","images":[],"options":{"A":"Three of them belong to blood group B","B":"Three of them belong to blood group O","C":"None of them belongs to blood group O","D":"Two of them belong to blood group B"},"answer":"A","explanation":"Three of them (75%) belong to blood group B while just one of them (25%) belongs to blood group O.  Note that this is a measure of probability (chance)","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>48","subject":"Biology","year":"2019","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"The cross between RrTt and rrtt where R is a gene for red colour and T for tallness will result in","images":[],"options":{"A":"all the offspring being tall with red fruits.","B":"25% tall with red fruits.","C":"50% tall with red fruits.","D":"75% tall with red fruits."},"answer":"B","explanation":"Given:  - RrTt (heterozygous for both traits: red color and tallness)  - rrtt (homozygous recessive for both traits: white color and short)    When we cross RrTt with rrtt:    - RrTt can produce gametes RT, Rt, rT, and rt.  - rrtt can only produce gametes rt.    Crossing these gametes gives us the following possible offspring genotypes:  - RT (red and tall)  - Rt (red and short)  - rT (white and tall)  - rt (white and short)    Now, let's count the phenotypic ratios:  - Red and tall (RT, Rt): 2 out of 4 possible combinations = 50%  - White and tall (rT): 1 out of 4 possible combinations = 25%  - White and short (rt): 1 out of 4 possible combinations = 25%    Therefore, based on the cross between RrTt and rrtt, the correct answer is: 50% tall with red fruits.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>49","subject":"Biology","year":"2019","type":"Objective","topic":"EVOLUTION : ADAPTIVE COLOURATION","question":"The yellow and black stripes on the body of wasps is an example of","images":[],"options":{"A":"mimicry.","B":"courtship behaviour.","C":"camouflage.","D":"warning colouration."},"answer":"D","explanation":"The yellow and black stripes on the body of wasps is an example of warning colouration. Warning colouration, also known as aposematism, is a type of adaptation where a species develops bright colours, patterns, or other physical characteristics that signal to predators that it is toxic, dangerous, or unpleasant to eat or attack.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2019>50","subject":"Biology","year":"2019","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"The biological importance of the dance by the worker honeybee is that it","images":[],"options":{"A":"acts as signal for mating.","B":"serves as a warning signal.","C":"signals the availability of food.","D":"serves as means of identifying members of the caste"},"answer":"C","explanation":"The dance by the worker honeybee signals the availability of food. This is known as the 'waggle dance'. The direction and duration of the dance communicates to other bees in the hive the direction and distance of a food source from the hive.","marks":"1","difficulty":"2"}];